                  className={`ro-cat-btn${activeCat === cat.id && !search ? " ro-cat-active" : ""}`}
                >
                  {cat.name}
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ── Main Content ── */}
      <main className="max-w-6xl mx-auto px-4 sm:px-6 py-6 pb-28 lg:pb-10">
        {/* Search bar */}
        <div
          className="flex items-center gap-3 px-4 py-2.5 mb-6"
          style={{
            background: "#ffffff",
            border: "1px solid #e2e8f0",
            borderRadius: "6px",
          }}
        >
          <Search className="w-4 h-4 shrink-0" style={{ color: "#94a3b8" }} />
          <input
            type="search"
            value={search}
            onChange={(e) => {
              setSearch(e.target.value);
              if (e.target.value) setActiveCat(null);
            }}
            placeholder="Search menu…"
            className="flex-1 bg-transparent outline-none text-sm"
            style={{ color: "#1e293b" }}
          />
          {search && (
            <button
              onClick={() => {
                setSearch("");
                setActiveCat(categories[0]?.id);
              }}
            >
              <X className="w-4 h-4" style={{ color: "#94a3b8" }} />
            </button>
          )}
        </div>

        {/* Section heading */}
        {!search && activeCatName && (
          <div className="flex items-center gap-3 mb-5">
            <h2 className="text-lg font-bold" style={{ color: "#1e293b" }}>
              {activeCatName}
            </h2>
            <div className="flex-1 ro-divider" />
          </div>
        )}
        {search && (
          <p className="text-sm mb-5" style={{ color: "#475569" }}>
            Results for <strong style={{ color: "#1e293b" }}>"{search}"</strong>
          </p>
        )}

        {/* Product grid */}
        {filtered.length === 0 ? (
          <div className="text-center py-20">
            <p className="text-base font-semibold" style={{ color: "#475569" }}>
              No items found
            </p>
            <p className="text-sm mt-1" style={{ color: "#94a3b8" }}>
              Try a different search or category.
            </p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {filtered.map((item, idx) => (
              <motion.div
                key={item.id}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: idx * 0.03, duration: 0.2 }}
                className="ro-card flex flex-col"
                onClick={() => setSelectedItem(item)}
              >
                {/* Item image */}
                {item.image_url ? (
                  <div
                    style={{
                      height: 180,
                      overflow: "hidden",
                      background: "#f1f5f9",
                    }}
                  >
                    <img
                      src={item.image_url}
                      alt={item.name}
                      className="w-full h-full object-cover"
                      onError={(e) => {
                        e.target.parentElement.style.display = "none";
                      }}
                    />
                  </div>
                ) : (
                  <div
                    className="flex items-center justify-center"
                    style={{ height: 140, background: "#f1f5f9" }}
                  >
                    <div
                      className="w-12 h-12 rounded-full flex items-center justify-center"
                      style={{ background: "#e2e8f0" }}
                    >
                      <ShoppingCart
                        className="w-5 h-5"
                        style={{ color: "#94a3b8" }}
                      />
                    </div>
                  </div>
                )}

                {/* Item info */}
                <div className="flex flex-col flex-1 p-4">
                  <h3
                    className="font-semibold text-sm leading-snug"
                    style={{ color: "#1e293b" }}
                  >
                    {item.name}
                  </h3>
                  {item.description && (
                    <p
                      className="text-xs mt-1 line-clamp-2 flex-1"
                      style={{ color: "#64748b" }}
                    >
                      {item.description}
                    </p>
                  )}
                  <div className="mt-4 flex items-center justify-between">
                    <span
                      className="font-bold text-base"
                      style={{ color: "#cc0000" }}
                    >
                      ${(item.price || 0).toFixed(2)}
                    </span>
                    <button
                      className="ro-btn-primary px-4 py-2 text-xs"
                      onClick={(e) => {
                        e.stopPropagation();
                        setSelectedItem(item);
                      }}
                    >
                      <Plus className="w-3 h-3" />
                      Add
                    </button>
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </main>

      {/* ── Mobile floating cart bar ── */}
      <AnimatePresence>
        {cartCount > 0 && (
          <motion.div
            initial={{ y: 80, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: 80, opacity: 0 }}
            className="fixed bottom-0 left-0 right-0 lg:hidden px-4 py-3"
            style={{
              background: "#ffffff",
              borderTop: "2px solid #cc0000",
              boxShadow: "0 -4px 16px rgba(0,0,0,0.10)",
            }}
          >
            <button
              onClick={() => navigate(`/order/${slug}/cart`)}
              className="ro-btn-primary w-full h-12 flex items-center justify-between px-5"
            >
              <span
                className="font-bold text-sm px-2 py-0.5 rounded"
                style={{ background: "rgba(255,255,255,0.2)" }}
              >
                {cartCount}
              </span>
              <span className="font-semibold text-sm">View Order</span>
              <span className="font-bold text-sm">${cartTotal.toFixed(2)}</span>
            </button>
          </motion.div>
        )}
      </AnimatePresence>

      {/* ── Modifier Modal ── */}
      <AnimatePresence>
        {selectedItem && (
          <OriginalModal
            item={selectedItem}
            merchantId={merchant?.id}
            merchantSlug={slug}
            onClose={() => setSelectedItem(null)}
          />
        )}
      </AnimatePresence>
    </div>
  );
};

export default RpowerOriginalMenuPage;

import React, { useMemo, useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { motion } from "framer-motion";
import { useCartStore } from "../../stores/cartStore";
import { apiService } from "../../context/AppContext";
import { Input } from "../../components/ui/input";
import { Label } from "../../components/ui/label";
import { Textarea } from "../../components/ui/textarea";
import { ArrowLeft, CreditCard, Loader2, Store } from "lucide-react";
import { toast } from "sonner";

/* Inject velocity theme variables (idempotent) */
const VELOCITY_STYLES = `
  :root {
    --vel-accent: #ff4405;
    --vel-accent-light: #fff1ed;
    --vel-bg: #f4f4f4;
    --vel-card: #ffffff;
    --vel-border: #e8e8e8;
    --vel-text: #111111;
  }
  .vel-accent-bg { background-color: var(--vel-accent) !important; color: #fff !important; }
`;

function useVelocityTheme() {
  useEffect(() => {
    const id = "velocity-theme";
    if (!document.getElementById(id)) {
      const el = document.createElement("style");
      el.id = id;
      el.textContent = VELOCITY_STYLES;
      document.head.appendChild(el);
    }
  }, []);
}

/* Floating-label input component */
const FloatInput = ({
  label,
  value,
  onChange,
  type = "text",
  required = false,
  autoComplete,
}) => {
  const filled = value && value.length > 0;
  return (
    <div className="relative">
      <input
        type={type}
        value={value}
        onChange={onChange}
        required={required}
        autoComplete={autoComplete}
        className={`peer w-full h-14 rounded-xl border border-[#e0e0e0] bg-white px-4 pt-5 pb-2 text-sm outline-none focus:border-[var(--vel-accent)] transition-colors`}
        placeholder=" "
      />
      <label
        className={`absolute left-4 top-1 text-[10px] font-semibold uppercase tracking-wide transition-all
          ${filled ? "text-[var(--vel-accent)]" : "text-black/40"}
          peer-focus:text-[var(--vel-accent)] peer-focus:top-1 peer-focus:text-[10px]
          peer-placeholder-shown:top-4 peer-placeholder-shown:text-sm peer-placeholder-shown:font-normal peer-placeholder-shown:normal-case peer-placeholder-shown:tracking-normal`}
      >
        {label}
        {required ? " *" : ""}
      </label>
    </div>
  );
};

/* Section card */
const Section = ({ title, children }) => (
  <div className="bg-white rounded-2xl p-5 shadow-sm">
    <h2 className="font-black text-sm uppercase tracking-wider text-black/40 mb-4">
      {title}
    </h2>
    {children}
  </div>
);

/* Toggle pill */
const PillToggle = ({ options, value, onChange }) => (
  <div className="flex gap-2">
    {options.map((opt) => (
      <button
        key={opt.value}
        type="button"
        onClick={() => onChange(opt.value)}
        className={`flex-1 h-10 rounded-xl font-bold text-sm transition-colors ${
          value === opt.value
            ? "vel-accent-bg"
            : "bg-[#f4f4f4] text-black/60 hover:bg-[#eee]"
        }`}
      >
        {opt.label}
      </button>
    ))}
  </div>
);

/* ─── Checkout Page ─────────────────────────────────────── */
const VelocityCheckoutPage = () => {
  useVelocityTheme();
  const { slug } = useParams();
  const navigate = useNavigate();
  const { items, merchantId, getSubtotal, getTax, clearCart } = useCartStore();

  const initialCustomer = {
    name: "",
    email: "",
    phone: "",
    address_line1: "",
    address_line2: "",
    city: "",
    state: "",
    zip_code: "",
  };

  const [submitting, setSubmitting] = useState(false);
  const [orderType, setOrderType] = useState("pickup");
  const [orderTiming, setOrderTiming] = useState("asap");
  const [scheduledDate, setScheduledDate] = useState("");
  const [scheduledTime, setScheduledTime] = useState("");
  const [paymentMethod, setPaymentMethod] = useState("");
  const [tip, setTip] = useState(0);
  const [tipSelection, setTipSelection] = useState(null);
  const [customTipInput, setCustomTipInput] = useState("");
  const [notes, setNotes] = useState("");
  const [customer, setCustomer] = useState(initialCustomer);

  const subtotal = getSubtotal();
  const tax = getTax();
  const deliveryFee = orderType === "delivery" ? 4.99 : 0;
  const isCardPayment = paymentMethod === "demo_card";
  const effectiveTip = isCardPayment ? tip : 0;
  const total = subtotal + tax + deliveryFee + effectiveTip;

  const dateOptions = useMemo(() => {
    return Array.from({ length: 7 }).map((_, idx) => {
      const d = new Date();
      d.setDate(d.getDate() + idx);
      return d.toISOString().split("T")[0];
    });
  }, []);

  const timeOptions = useMemo(() => {
    const options = [];
    for (let h = 9; h <= 21; h++) {
      for (let m = 0; m < 60; m += 15) {
        if (h === 21 && m > 0) continue;
        const value = `${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}`;
        options.push(value);
      }
    }
    return options;
  }, []);

  const validate = () => {
    if (!customer.name.trim()) return "Please enter your full name";
    if (!customer.phone.trim()) return "Please enter your phone number";
    if (orderType === "delivery") {
      if (
        !customer.address_line1.trim() ||
        !customer.city.trim() ||
        !customer.zip_code.trim()
      ) {
        return "Please complete delivery address (street, city, ZIP)";
      }
    }
    if (orderTiming !== "asap" && (!scheduledDate || !scheduledTime)) {
      return "Please select both a date and time";
    }
    if (!paymentMethod) return "Please select a payment method";
    if (!items.length) return "Your cart is empty";
    if (!merchantId)
      return "Merchant context is missing. Please reopen the menu and try again.";
    return null;
  };

  const handleSubmit = async () => {
    const err = validate();
    if (err) {
      toast.error(err);
      return;
    }
    setSubmitting(true);
    try {
      const paymentMethodMap = {
        demo_card: "mock_card",
        cash: "cash",
        pay_at_store: "pay_at_store",
      };

      const orderData = {
        merchant_id: merchantId,
        customer: {
          name: customer.name,
          email: customer.email || "guest@rnoo.com",
          phone: customer.phone,
          address_line1:
            orderType === "delivery" ? customer.address_line1 : null,
          address_line2:
            orderType === "delivery" ? customer.address_line2 : null,
          city: orderType === "delivery" ? customer.city : null,
          state: orderType === "delivery" ? customer.state : null,
          zip_code: orderType === "delivery" ? customer.zip_code : null,
        },
        delivery_type: orderType === "delivery" ? "DELIVERY" : "TAKEOUT",
        items: items.map((item) => ({
          menu_item_id: item.itemId,
          name: item.name,
          quantity: item.quantity,
          unit_price: item.basePrice,
          plu: item.plu || "",
          shepherd_pos_id: item.shepherd_pos_id || "",
          modifiers: (item.modifiers || []).map((mod) => ({
            group_id: mod.group_id || "default",
            group_name: mod.group_name || "Modifier",
            option_id: mod.option_id || "default",
            option_name: mod.option_name || mod.name || "Option",
            price: mod.price || 0,
            plu: mod.plu || "",
            shepherd_pos_id: mod.shepherd_pos_id || "",
          })),
          special_instructions: item.specialInstructions || null,
        })),
        payment: {
          method: paymentMethodMap[paymentMethod] || "cash",
          amount: total,
          tip: effectiveTip,
          status: "pending",
        },
        order_timing: orderTiming === "asap" ? "ASAP" : "FUTURE",
        scheduled_date: orderTiming === "asap" ? null : scheduledDate,
        scheduled_time: orderTiming === "asap" ? null : scheduledTime,
        notes: notes || null,
      };

      const res = await apiService.createOrder(orderData);
      clearCart();
      setCustomer(initialCustomer);
      setNotes("");
      setOrderTiming("asap");
      setScheduledDate("");
      setScheduledTime("");
      setPaymentMethod("");
      setTip(0);
      setTipSelection(null);
      setCustomTipInput("");
      toast.success("Order placed!");
      navigate(
        `/order-confirmation?orderId=${encodeURIComponent(res.data.id)}&merchantSlug=${encodeURIComponent(slug)}&paymentMethod=${encodeURIComponent(paymentMethod)}`,
      );
    } catch (err) {
      console.error("Failed to place order:", err);
      let msg = "Failed to place order";
      const detail = err.response?.data?.detail;
      if (typeof detail === "string") msg = detail;
      if (Array.isArray(detail) && detail.length > 0) {
        msg = detail
          .map((e) => e.msg || e.message || "Validation error")
          .join(", ");
      }
      toast.error(msg);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#f4f4f4] text-[#111]">
      {/* sticky header */}
      <div className="sticky top-0 z-20 bg-white border-b border-[#eee] px-4 py-4 flex items-center gap-3">
        <button
          type="button"
          onClick={() => navigate(`/order/${slug}/cart`)}
          className="w-9 h-9 rounded-full bg-[#f4f4f4] flex items-center justify-center"
        >
          <ArrowLeft className="w-5 h-5" />
        </button>
        <h1 className="font-black text-xl flex-1">Checkout</h1>
        <span className="font-bold text-base text-[var(--vel-accent)]">
          ${total.toFixed(2)}
        </span>
      </div>

      <motion.div
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        className="max-w-2xl mx-auto px-4 py-5 space-y-4 pb-32"
      >
        {/* ── Express Checkout ── */}
        <Section title="Express Checkout">
          <div className="grid grid-cols-2 gap-3">
            <button
              type="button"
              onClick={() =>
                toast.info("Apple Pay is not available in demo mode")
              }
              className="h-12 rounded-xl bg-black text-white font-bold text-sm flex items-center justify-center gap-2"
            >
              <svg
                viewBox="0 0 24 24"
                className="w-5 h-5 fill-white"
                aria-hidden
              >
                <path d="M18.71 19.5c-.83 1.24-1.71 2.45-3.05 2.47-1.34.03-1.77-.79-3.29-.79-1.53 0-2 .77-3.27.82-1.31.05-2.3-1.32-3.14-2.53C4.25 17 2.94 12.45 4.7 9.39c.87-1.52 2.43-2.48 4.12-2.51 1.28-.02 2.5.87 3.29.87.78 0 2.26-1.07 3.8-.91.65.03 2.47.26 3.64 1.98-.09.06-2.17 1.28-2.15 3.81.03 3.02 2.65 4.03 2.68 4.04-.03.07-.42 1.44-1.38 2.83M13 3.5c.73-.83 1.94-1.46 2.94-1.5.13 1.17-.34 2.35-1.04 3.19-.69.85-1.83 1.51-2.95 1.42-.15-1.15.41-2.35 1.05-3.11z" />
              </svg>
              Apple Pay
            </button>
            <button
              type="button"
              onClick={() =>
                toast.info("Google Pay is not available in demo mode")
              }
              className="h-12 rounded-xl border-2 border-[#eee] bg-white font-bold text-sm flex items-center justify-center gap-2"
            >
              <svg viewBox="0 0 24 24" className="w-5 h-5" aria-hidden>
                <path
                  fill="#4285F4"
                  d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                />
                <path
                  fill="#34A853"
                  d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                />
                <path
                  fill="#FBBC05"
                  d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                />
                <path
                  fill="#EA4335"
                  d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                />
              </svg>
              Google Pay
            </button>
          </div>
          <div className="flex items-center gap-3 mt-4">
            <div className="flex-1 h-px bg-[#e8e8e8]" />
            <span className="text-xs font-semibold text-black/40 uppercase tracking-widest">
              or fill in details
            </span>
            <div className="flex-1 h-px bg-[#e8e8e8]" />
          </div>
        </Section>

        {/* ── Contact ── */}
        <Section title="Contact">
          <div className="space-y-3">
            <FloatInput
              label="Full Name"
              required
              value={customer.name}
              onChange={(e) =>
                setCustomer({ ...customer, name: e.target.value })
              }
              autoComplete="name"
            />
            <FloatInput
              label="Phone"
              required
              type="tel"
              value={customer.phone}
              onChange={(e) =>
                setCustomer({ ...customer, phone: e.target.value })
              }
              autoComplete="tel"
            />
            <FloatInput
              label="Email"
              type="email"
              value={customer.email}
              onChange={(e) =>
                setCustomer({ ...customer, email: e.target.value })
              }
              autoComplete="email"
            />
          </div>
        </Section>

        {/* ── Delivery / Pickup ── */}
        <Section title="Order Type">
          <PillToggle
            options={[
              { value: "pickup", label: "Pickup" },
              { value: "delivery", label: "Delivery" },
            ]}
            value={orderType}
            onChange={setOrderType}
          />

          {orderType === "delivery" && (
            <div className="mt-4 space-y-3">
              <FloatInput
                label="Address"
                required
                value={customer.address_line1}
                onChange={(e) =>
                  setCustomer({ ...customer, address_line1: e.target.value })
                }
                autoComplete="address-line1"
              />
              <FloatInput
                label="Apt / Suite"
                value={customer.address_line2}
                onChange={(e) =>
                  setCustomer({ ...customer, address_line2: e.target.value })
                }
                autoComplete="address-line2"
              />
              <div className="grid grid-cols-2 gap-3">
                <FloatInput
                  label="City"
                  required
                  value={customer.city}
                  onChange={(e) =>
                    setCustomer({ ...customer, city: e.target.value })
                  }
                  autoComplete="address-level2"
                />
                <FloatInput
                  label="ZIP"
                  required
                  value={customer.zip_code}
                  onChange={(e) =>
                    setCustomer({ ...customer, zip_code: e.target.value })
                  }
                  autoComplete="postal-code"
                />
              </div>
            </div>
          )}
        </Section>

        {/* ── Timing ── */}
        <Section title="When">
          <PillToggle
            options={[
              { value: "asap", label: "ASAP" },
              { value: "future", label: "Schedule" },
            ]}
            value={orderTiming}
            onChange={setOrderTiming}
          />
          {orderTiming === "future" && (
            <div className="grid grid-cols-2 gap-3 mt-4">
              <div>
                <Label className="text-xs font-semibold uppercase tracking-wide text-black/50">
                  Date
                </Label>
                <select
                  className="w-full mt-1 h-12 px-3 rounded-xl border border-[#e0e0e0] bg-white text-sm outline-none focus:border-[var(--vel-accent)]"
                  value={scheduledDate}
                  onChange={(e) => setScheduledDate(e.target.value)}
                >
                  <option value="">Select date</option>
                  {dateOptions.map((d) => (
                    <option key={d} value={d}>
                      {d}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <Label className="text-xs font-semibold uppercase tracking-wide text-black/50">
                  Time
                </Label>
                <select
                  className="w-full mt-1 h-12 px-3 rounded-xl border border-[#e0e0e0] bg-white text-sm outline-none focus:border-[var(--vel-accent)]"
                  value={scheduledTime}
                  onChange={(e) => setScheduledTime(e.target.value)}
                >
                  <option value="">Select time</option>
                  {timeOptions.map((t) => (
                    <option key={t} value={t}>
                      {t}
                    </option>
                  ))}
                </select>
              </div>
            </div>
          )}
        </Section>

        {/* ── Payment ── */}
        <Section title="Payment">
          <div className="space-y-3">
            {[
              { id: "demo_card", label: "Demo Credit Card", Icon: CreditCard },
              { id: "pay_at_store", label: "Pay at Store", Icon: Store },
            ].map(({ id, label, Icon }) => (
              <button
                key={id}
                type="button"
                onClick={() => {
                  setPaymentMethod(id);
                  if (id !== "demo_card") {
                    setTip(0);
                    setTipSelection(null);
                    setCustomTipInput("");
                  }
                }}
                className={`w-full h-13 px-4 rounded-xl border-2 flex items-center gap-3 text-sm font-semibold transition-colors ${
                  paymentMethod === id
                    ? "border-[var(--vel-accent)] bg-[var(--vel-accent-light)] text-[var(--vel-accent)]"
                    : "border-[#e8e8e8] bg-white text-black/70 hover:border-black/30"
                }`}
                style={{ height: "52px" }}
              >
                <Icon className="w-4 h-4 shrink-0" />
                {label}
                {paymentMethod === id && (
                  <span className="ml-auto text-[var(--vel-accent)] font-black">
                    ✓
                  </span>
                )}
              </button>
            ))}
            {isCardPayment && (
              <p className="text-xs text-black/40 pt-1">
                Demo mode — no real card data is collected.
              </p>
            )}
          </div>
        </Section>

        {/* ── Tip (card only) ── */}
        {isCardPayment && (
          <Section title="Tip">
            <div className="flex gap-2 flex-wrap">
              {[10, 15, 20].map((pct) => (
                <button
                  key={pct}
                  type="button"
                  onClick={() => {
                    setTipSelection(pct);
                    setTip(Math.round(subtotal * (pct / 100) * 100) / 100);
                    setCustomTipInput("");
                  }}
                  className={`flex-1 h-11 rounded-xl border-2 font-bold text-sm transition-colors ${
                    tipSelection === pct
                      ? "border-[var(--vel-accent)] bg-[var(--vel-accent)] text-white"
                      : "border-[#e8e8e8] bg-white text-black/70 hover:border-black/30"
                  }`}
                >
                  {pct}%
                </button>
              ))}
              <button
                type="button"
                onClick={() => {
                  setTipSelection("custom");
                  setTip(parseFloat(customTipInput) || 0);
                }}
                className={`flex-1 h-11 rounded-xl border-2 font-bold text-sm transition-colors ${
                  tipSelection === "custom"
                    ? "border-[var(--vel-accent)] bg-[var(--vel-accent)] text-white"
                    : "border-[#e8e8e8] bg-white text-black/70 hover:border-black/30"
                }`}
              >
                Custom
              </button>
            </div>

            {tipSelection === "custom" && (
              <div className="mt-3">
                <FloatInput
                  label="Custom Tip ($)"
                  type="number"
                  value={customTipInput}
                  onChange={(e) => {
                    setCustomTipInput(e.target.value);
                    setTip(parseFloat(e.target.value) || 0);
                  }}
                />
              </div>
            )}

            {tip > 0 && (
              <p className="text-sm text-black/50 mt-2">
                Tip: ${tip.toFixed(2)}
              </p>
            )}
          </Section>
        )}

        {/* ── Notes ── */}
        <Section title="Notes">
          <Textarea
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
            rows={2}
            placeholder="Anything else we should know?"
            className="rounded-xl border-[#e0e0e0] text-sm resize-none"
          />
        </Section>

        {/* ── Order Summary ── */}
        <Section title="Order Summary">
          <div className="space-y-2 text-sm">
            {items.map((item) => (
              <div key={item.id} className="flex justify-between text-black/70">
                <span>
                  {item.quantity}× {item.name}
                </span>
                <span>${item.totalPrice.toFixed(2)}</span>
              </div>
            ))}
            <div className="h-px bg-[#eee] my-2" />
            <div className="flex justify-between text-black/55">
              <span>Subtotal</span>
              <span>${subtotal.toFixed(2)}</span>
            </div>
            <div className="flex justify-between text-black/55">
              <span>Tax (est.)</span>
              <span>${tax.toFixed(2)}</span>
            </div>
            {orderType === "delivery" && (
              <div className="flex justify-between text-black/55">
                <span>Delivery Fee</span>
                <span>${deliveryFee.toFixed(2)}</span>
              </div>
            )}
            {effectiveTip > 0 && (
              <div className="flex justify-between text-black/55">
                <span>Tip</span>
                <span>${effectiveTip.toFixed(2)}</span>
              </div>
            )}
            <div className="flex justify-between font-black text-base pt-2 border-t border-[#eee]">
              <span>Total</span>
              <span>${total.toFixed(2)}</span>
            </div>
          </div>
        </Section>
      </motion.div>

      {/* sticky CTA */}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-[#eee] px-4 py-4 max-w-2xl mx-auto">
        <button
          type="button"
          onClick={handleSubmit}
          disabled={submitting}
          className="w-full h-14 rounded-2xl vel-accent-bg font-black text-lg flex items-center justify-center gap-2 disabled:opacity-60 active:scale-[0.98] transition-all"
        >
          {submitting ? (
            <>
              <Loader2 className="w-5 h-5 animate-spin" />
              Placing Order...
            </>
          ) : (
            `Place Order — $${total.toFixed(2)}`
          )}
        </button>
      </div>
    </div>
  );
};

export default VelocityCheckoutPage;

import React, { useCallback, useEffect, useMemo, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { motion } from "framer-motion";
import { apiService } from "../../context/AppContext";
import { useOrderWebSocket } from "../../hooks/useOrderWebSocket";
import { AlertCircle, ArrowLeft, RefreshCw } from "lucide-react";
import { toast } from "sonner";

/* Inject velocity theme variables (idempotent) */
const VELOCITY_STYLES = `
  :root {
    --vel-accent: #ff4405;
  }
  .vel-accent-bg { background-color: var(--vel-accent) !important; color: #fff !important; }
`;

function useVelocityTheme() {
  useEffect(() => {
    const id = "velocity-theme";
    if (!document.getElementById(id)) {
      const el = document.createElement("style");
      el.id = id;
      el.textContent = VELOCITY_STYLES;
      document.head.appendChild(el);
    }
  }, []);
}

/* Compact horizontal step tracker */
const TRACK_STEPS = [
  { key: "pending", label: "Received" },
  { key: "confirmed", label: "Received" }, // alias — maps to same visual step
  { key: "preparing", label: "Preparing" },
  { key: "ready", label: "Ready" },
  { key: "delivered", label: "Delivered" },
];

/* Deduplicated display steps */
const DISPLAY_STEPS = [
  { label: "Received", statuses: ["pending", "confirmed"] },
  { label: "Preparing", statuses: ["preparing"] },
  { label: "Ready", statuses: ["ready"] },
  { label: "Delivered", statuses: ["delivered"] },
];

const HorizontalTracker = ({ status }) => {
  const activeIdx = useMemo(() => {
    for (let i = 0; i < DISPLAY_STEPS.length; i++) {
      if (DISPLAY_STEPS[i].statuses.includes(status)) return i;
    }
    return 0;
  }, [status]);

  return (
    <div className="flex items-center w-full px-2">
      {DISPLAY_STEPS.map((step, idx) => {
        const completed = idx < activeIdx;
        const current = idx === activeIdx;
        const isLast = idx === DISPLAY_STEPS.length - 1;

        return (
          <React.Fragment key={step.label}>
            {/* dot + label */}
            <div className="flex flex-col items-center gap-1.5 shrink-0">
              <motion.div
                initial={{ scale: 0.6 }}
                animate={{ scale: 1 }}
                className={`w-4 h-4 rounded-full border-2 transition-colors ${
                  completed
                    ? "bg-[var(--vel-accent)] border-[var(--vel-accent)]"
                    : current
                      ? "bg-white border-[var(--vel-accent)]"
                      : "bg-white border-[#ccc]"
                } ${current ? "ring-4 ring-[var(--vel-accent)]/20" : ""}`}
              />
              <span
                className={`text-[10px] font-bold uppercase tracking-wide whitespace-nowrap ${
                  current
                    ? "text-[var(--vel-accent)]"
                    : completed
                      ? "text-black/70"
                      : "text-black/30"
                }`}
              >
                {step.label}
              </span>
            </div>

            {/* connector line */}
            {!isLast && (
              <div className="flex-1 h-0.5 mx-1 mb-5 rounded-full overflow-hidden bg-[#e8e8e8]">
                <motion.div
                  className="h-full rounded-full"
                  style={{ backgroundColor: "var(--vel-accent)" }}
                  initial={{ width: 0 }}
                  animate={{ width: completed ? "100%" : "0%" }}
                  transition={{ duration: 0.5, ease: "easeOut" }}
                />
              </div>
            )}
          </React.Fragment>
        );
      })}
    </div>
  );
};

/* ─── Order Tracking Page ─────────────────────────────────── */
const VelocityOrderTrackingPage = () => {
  useVelocityTheme();
  const { orderId } = useParams();
  const navigate = useNavigate();
  const [order, setOrder] = useState(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  const trackingMerchantId = order?.merchant_id;

  const { isConnected } = useOrderWebSocket({
    merchantId: trackingMerchantId,
    onOrderUpdate: (updated) => {
      if (updated && String(updated.id) === String(orderId)) {
        setOrder(updated);
      }
    },
  });

  const loadOrder = useCallback(
    async (silent = false) => {
      try {
        if (silent) setRefreshing(true);
        else setLoading(true);
        const res = await apiService.getOrderPublic(orderId, {
          _ts: Date.now(),
        });
        setOrder(res.data);
      } catch (err) {
        console.error("Failed to load order:", err);
        if (!silent) toast.error("Order not found");
      } finally {
        if (silent) setRefreshing(false);
        else setLoading(false);
      }
    },
    [orderId],
  );

  useEffect(() => {
    loadOrder();
  }, [loadOrder]);

  /* auto-poll every 10 s */
  useEffect(() => {
    const id = setInterval(() => loadOrder(true), 10000);
    return () => clearInterval(id);
  }, [loadOrder]);

  if (loading) {
    return (
      <div className="min-h-screen bg-[#f4f4f4] flex items-center justify-center">
        <div className="animate-spin rounded-full h-10 w-10 border-4 border-[var(--vel-accent)] border-t-transparent" />
      </div>
    );
  }

  if (!order) {
    return (
      <div className="min-h-screen bg-[#f4f4f4] flex flex-col items-center justify-center gap-4 px-6 text-center">
        <AlertCircle className="w-12 h-12 text-black/25" />
        <h2 className="text-xl font-black">Order Not Found</h2>
        <button
          onClick={() => navigate("/")}
          className="h-12 px-8 rounded-2xl vel-accent-bg font-bold"
        >
          Back Home
        </button>
      </div>
    );
  }

  const subtotal = order.subtotal || 0;
  const tax = order.tax || 0;
  const tip = order.tip || 0;
  const total = order.total || 0;

  return (
    <div className="min-h-screen bg-[#f4f4f4] text-[#111]">
      {/* header */}
      <div className="sticky top-0 z-10 bg-white border-b border-[#eee] px-4 py-4 flex items-center gap-3">
        <button
          type="button"
          onClick={() => navigate("/")}
          className="w-9 h-9 rounded-full bg-[#f4f4f4] flex items-center justify-center"
        >
          <ArrowLeft className="w-5 h-5" />
        </button>
        <div className="flex-1 min-w-0">
          <h1 className="font-black text-lg leading-tight truncate">
            Order #{order.order_number || orderId.slice(-6).toUpperCase()}
          </h1>
          <p className="text-xs text-black/40 capitalize">{order.status}</p>
        </div>
        <div className="flex items-center gap-2">
          {isConnected && (
            <span
              className="w-2 h-2 rounded-full bg-green-500 animate-pulse"
              title="Live updates"
            />
          )}
          <button
            type="button"
            onClick={() => loadOrder(true)}
            className="w-9 h-9 rounded-full bg-[#f4f4f4] flex items-center justify-center"
            aria-label="Refresh"
          >
            <RefreshCw
              className={`w-4 h-4 ${refreshing ? "animate-spin" : ""}`}
            />
          </button>
        </div>
      </div>

      <div className="max-w-2xl mx-auto px-4 py-6 space-y-4">
        {/* ── Horizontal step tracker ── */}
        <motion.div
          initial={{ opacity: 0, y: -8 }}
          animate={{ opacity: 1, y: 0 }}
          className="bg-white rounded-2xl px-5 pt-6 pb-5 shadow-sm"
        >
          <HorizontalTracker status={order.status} />

          {/* status message */}
          <div className="mt-5 text-center">
            {order.status === "ready" || order.status === "delivered" ? (
              <p className="font-black text-[var(--vel-accent)] text-base">
                {order.status === "ready"
                  ? "Your order is ready! 🎉"
                  : "Order delivered ✓"}
              </p>
            ) : (
              <p className="text-sm text-black/50 font-semibold">
                {order.status === "preparing"
                  ? "Kitchen is working on your order…"
                  : "Order received — confirming with kitchen…"}
              </p>
            )}
          </div>
        </motion.div>

        {/* ── Receipt summary (text-only) ── */}
        <motion.div
          initial={{ opacity: 0, y: 8 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="bg-white rounded-2xl px-5 py-5 shadow-sm"
        >
          <h2 className="text-xs font-black uppercase tracking-widest text-black/40 mb-4">
            Receipt
          </h2>

          {/* items */}
          <div className="space-y-1.5 mb-4">
            {(order.items || []).map((item, idx) => (
              <div
                key={idx}
                className="flex justify-between text-sm text-black/70"
              >
                <span>
                  {item.quantity}× {item.name}
                  {item.modifiers?.length > 0 && (
                    <span className="text-xs text-black/40 ml-1">
                      ({item.modifiers.map((m) => m.option_name).join(", ")})
                    </span>
                  )}
                </span>
                <span>
                  ${((item.unit_price || 0) * item.quantity).toFixed(2)}
                </span>
              </div>
            ))}
          </div>

          <div className="h-px bg-[#eee] mb-3" />

          <div className="space-y-1 text-sm">
            <div className="flex justify-between text-black/55">
              <span>Subtotal</span>
              <span>${subtotal.toFixed(2)}</span>
            </div>
            <div className="flex justify-between text-black/55">
              <span>Tax</span>
              <span>${tax.toFixed(2)}</span>
            </div>
            {tip > 0 && (
              <div className="flex justify-between text-black/55">
                <span>Tip</span>
                <span>${tip.toFixed(2)}</span>
              </div>
            )}
            <div className="flex justify-between font-black text-base pt-2 border-t border-[#eee]">
              <span>Total</span>
              <span>${total.toFixed(2)}</span>
            </div>
          </div>

          {/* order meta */}
          <div className="mt-4 pt-3 border-t border-[#eee] space-y-1 text-xs text-black/40">
            {order.delivery_type && (
              <p>
                <span className="font-semibold">Type:</span>{" "}
                {order.delivery_type === "DELIVERY" ? "Delivery" : "Pickup"}
              </p>
            )}
            {order.customer?.name && (
              <p>
                <span className="font-semibold">Name:</span>{" "}
                {order.customer.name}
              </p>
            )}
            <p>
              <span className="font-semibold">Order ID:</span>{" "}
              <span className="font-mono">{orderId}</span>
            </p>
          </div>
        </motion.div>
      </div>
    </div>
  );
};

export default VelocityOrderTrackingPage;
